      out.write("</div>\n");
      out.write("\n");
      out.write("<script src=\"https://cdn.jsdelivr.net/npm/bootstrap@5.3.0/dist/js/bootstrap.bundle.min.js\"></script>\n");
      out.write("<script>\n");
      out.write("// 공통 토스트 함수\n");
      out.write("function showToast(message, type) {\n");
      out.write("    type = type || 'success'; // success, danger, warning, info\n");
      out.write("    const toast    = document.getElementById('appToast');\n");
      out.write("    const toastMsg = document.getElementById('appToastMsg');\n");
      out.write("\n");
      out.write("    // 색상 설정\n");
      out.write("    toast.className = 'toast align-items-center border-0 shadow text-white';\n");
      out.write("    if (type === 'success') toast.classList.add('bg-success');\n");
      out.write("    else if (type === 'danger')  toast.classList.add('bg-danger');\n");
      out.write("    else if (type === 'warning') toast.classList.add('bg-warning', 'text-dark');\n");
      out.write("    else if (type === 'info')    toast.classList.add('bg-primary');\n");
      out.write("\n");
      out.write("    toastMsg.innerText = message;\n");
      out.write("    const bsToast = new bootstrap.Toast(toast, { delay: 3000 });\n");
      out.write("    bsToast.show();\n");
      out.write("}\n");
      out.write("\n");
      out.write("// alert 대체 함수 (기존 코드와 호환)\n");
      out.write("function showAlert(message, type) {\n");
      out.write("    showToast(message, type || 'info');\n");
      out.write("}\n");
      out.write("</script>\n");
      out.write("\r\n");
      out.write("\r\n");
      out.write("<script>\r\n");
      out.write("// 매장 선택\r\n");
      out.write("function selectStore(storeId, storeName) {\r\n");
      out.write("    document.querySelectorAll('.store-item').forEach(el => el.classList.remove('active'));\r\n");
      out.write("    const item = document.getElementById('store-item-' + storeId);\r\n");
      out.write("    if (item) item.classList.add('active');\r\n");
      out.write("    document.getElementById('selectedStoreName').innerHTML =\r\n");
      out.write("        '<i class=\"fa-solid fa-store me-2 text-primary\"></i>' + storeName;\r\n");
      out.write("    // TODO: 해당 매장 직원 목록 AJAX 로드\r\n");
      out.write("    location.href = 'StoreMemberManage?storeId=' + storeId;\r\n");
      out.write("}\r\n");
      out.write("\r\n");
      out.write("// 역할 로드\r\n");
      out.write("async function loadRoleOptions() {\r\n");
      out.write("    try {\r\n");
      out.write("        const storeId = '");
      out.print(currentStoreId);
      out.write("';\r\n");
      out.write("        if (!storeId) return;\r\n");
      out.write("        const res  = await fetch('GetRoles?storeId=' + encodeURIComponent(storeId));\r\n");
      out.write("        const data = await res.json();\r\n");
      out.write("        if (data.status === 'success') {\r\n");
      out.write("            const roleFilterEl = document.getElementById('roleFilter');\r\n");
      out.write("            document.querySelectorAll('.role-select').forEach(select => {\r\n");
      out.write("                const cur = select.dataset.current || '0';\r\n");
      out.write("                data.list.forEach(role => {\r\n");
      out.write("                    const opt = document.createElement('option');\r\n");
      out.write("                    opt.value = role.roleId;\r\n");
      out.write("                    opt.text  = role.roleName;\r\n");
      out.write("                    opt.dataset.wage = role.wage;\r\n");
      out.write("                    if (String(role.roleId) === String(cur)) opt.selected = true;\r\n");
      out.write("                    select.appendChild(opt);\r\n");
      out.write("                });\r\n");
      out.write("            });\r\n");
      out.write("            data.list.forEach(role => {\r\n");
      out.write("                const opt = document.createElement('option');\r\n");
      out.write("                opt.value = role.roleName;\r\n");
      out.write("                opt.text  = role.roleName;\r\n");
      out.write("                roleFilterEl.appendChild(opt);\r\n");
      out.write("            });\r\n");
      out.write("        }\r\n");
      out.write("    } catch (e) { console.error(e); }\r\n");
      out.write("}\r\n");
      out.write("\r\n");
      out.write("// 역할 지정\r\n");
      out.write("async function assignRole(memId, select) {\r\n");
      out.write("    const roleId   = select.value;\r\n");
      out.write("    const roleName = select.options[select.selectedIndex].text;\r\n");
      out.write("    if (!confirm('\"' + roleName + '\" 역할을 지정하시겠습니까?')) {\r\n");
      out.write("        select.value = select.dataset.current || '0';\r\n");
      out.write("        return;\r\n");
      out.write("    }\r\n");
      out.write("    const params = new URLSearchParams();\r\n");
      out.write("    params.append('memId', memId);\r\n");
      out.write("    params.append('roleId', roleId);\r\n");
      out.write("    try {\r\n");
      out.write("        const res  = await fetch('RoleAssign', { method: 'POST', body: params });\r\n");
      out.write("        const data = await res.json();\r\n");
      out.write("        if (data.status === 'success') {\r\n");
      out.write("            select.dataset.current = roleId;\r\n");
      out.write("            const wageEl = document.getElementById('wage-' + memId);\r\n");
      out.write("            if (wageEl) {\r\n");
      out.write("                wageEl.innerText = data.wage > 0 ? Number(data.wage).toLocaleString() + '원' : '-';\r\n");
      out.write("                const badge = document.createElement('span');\r\n");
      out.write("                badge.className = 'badge bg-success ms-1';\r\n");
      out.write("                badge.innerText = '저장됨';\r\n");
      out.write("                wageEl.after(badge);\r\n");
      out.write("                setTimeout(() => badge.remove(), 2000);\r\n");
      out.write("            }\r\n");
      out.write("        } else {\r\n");
      out.write("            showToast(data.message, 'danger');\r\n");
      out.write("            select.value = select.dataset.current || '0';\r\n");
      out.write("        }\r\n");
      out.write("    } catch (e) {\r\n");
      out.write("        showToast('통신 오류가 발생했습니다.', 'danger');\r\n");
      out.write("    }\r\n");
      out.write("}\r\n");
      out.write("\r\n");
      out.write("// 직원 제외\r\n");
      out.write("function removeStaff(id, name) {\r\n");
      out.write("    if (confirm(\"'\" + name + \"' 직원을 매장에서 제외하시겠습니까?\")) {\r\n");
      out.write("        location.href = 'AdminMemberDelete?id=' + id;\r\n");
      out.write("    }\r\n");
      out.write("}\r\n");
      out.write("\r\n");
      out.write("// 필터\r\n");
      out.write("function filterMembers() {\r\n");
      out.write("    const nameFilter = document.getElementById('searchInput').value.toUpperCase();\r\n");
      out.write("    const roleFilter = document.getElementById('roleFilter').value;\r\n");
      out.write("    const typeFilter = document.getElementById('typeFilter').value;\r\n");
      out.write("    document.querySelectorAll('#memberTable tbody tr').forEach(tr => {\r\n");
      out.write("        if (tr.cells.length < 2) return;\r\n");
      out.write("        const name    = tr.cells[0].innerText;\r\n");
      out.write("        const phone   = tr.cells[1].innerText;\r\n");
      out.write("        const roleSelect = tr.querySelector('.role-select');\r\n");
      out.write("        const isAdmin = name.includes('점장');\r\n");
      out.write("        const nameMatch = name.toUpperCase().includes(nameFilter) || phone.toUpperCase().includes(nameFilter);\r\n");
      out.write("        let roleMatch = true;\r\n");
      out.write("        if (roleFilter === 'unassigned') roleMatch = roleSelect && roleSelect.value === '0';\r\n");
      out.write("        else if (roleFilter !== '') roleMatch = roleSelect && roleSelect.options[roleSelect.selectedIndex].text === roleFilter;\r\n");
      out.write("        let typeMatch = true;\r\n");
      out.write("        if (typeFilter === 'staff') typeMatch = !isAdmin;\r\n");
      out.write("        if (typeFilter === 'admin') typeMatch = isAdmin;\r\n");
      out.write("        tr.style.display = (nameMatch && roleMatch && typeMatch) ? '' : 'none';\r\n");
      out.write("    });\r\n");
      out.write("}\r\n");
      out.write("\r\n");
      out.write("// 소속 신청 승인/거절\r\n");
      out.write("async function handleJoin(memId, storeId, action) {\r\n");
      out.write("    const label = action === 'approve' ? '승인' : '거절';\r\n");
      out.write("    if (!confirm(memId + ' 직원을 ' + label + '하시겠습니까?')) return;\r\n");
      out.write("\r\n");
      out.write("    const params = new URLSearchParams();\r\n");
      out.write("    params.append('action',  action);\r\n");
      out.write("    params.append('memId',   memId);\r\n");
      out.write("    params.append('storeId', storeId);\r\n");
      out.write("\r\n");
      out.write("    try {\r\n");
      out.write("        const res  = await fetch('StoreMemberManage', { method: 'POST', body: params });\r\n");
      out.write("        const data = await res.json();\r\n");
      out.write("        showToast(data.message, data.status === 'success' ? 'success' : 'danger');\r\n");
      out.write("        if (data.status === 'success') location.reload();\r\n");
      out.write("    } catch (e) {\r\n");
      out.write("        showToast('통신 오류가 발생했습니다.', 'danger');\r\n");
      out.write("    }\r\n");
      out.write("}\r\n");
      out.write("\r\n");
      out.write("// 새 매장 신청 (기능 연결)\r\n");
      out.write("async function requestCreateStore() {\r\n");
      out.write("    const storeId   = document.getElementById('newStoreId').value.trim();\r\n");
      out.write("    const storeName = document.getElementById('newStoreName').value.trim();\r\n");
      out.write("    if (!storeId || !storeName) {\r\n");
      out.write("        showToast('매장 코드와 이름을 입력해주세요.', 'warning');\r\n");
      out.write("        return;\r\n");
      out.write("    }\r\n");
      out.write("\r\n");
      out.write("    const params = new URLSearchParams();\r\n");
      out.write("    params.append('action',    'createStore');\r\n");
      out.write("    params.append('storeId',   storeId);\r\n");
      out.write("    params.append('storeName', storeName);\r\n");
      out.write("\r\n");
      out.write("    try {\r\n");
      out.write("        const res  = await fetch('StoreMemberManage', { method: 'POST', body: params });\r\n");
      out.write("        const data = await res.json();\r\n");
      out.write("        showToast(data.message, data.status === 'success' ? 'success' : 'danger');\r\n");
      out.write("        if (data.status === 'success') {\r\n");
      out.write("            bootstrap.Modal.getInstance(document.getElementById('addStoreModal')).hide();\r\n");
      out.write("            location.reload();\r\n");
      out.write("        }\r\n");
      out.write("    } catch (e) {\r\n");
      out.write("        showToast('통신 오류가 발생했습니다.', 'danger');\r\n");
      out.write("    }\r\n");
      out.write("}\r\n");
      out.write("\r\n");
      out.write("// 매장 설정 저장 (UI only - 주휴수당 기능은 추후 연결)\r\n");
      out.write("function saveStoreSetting() {\r\n");
      out.write("    showToast('설정이 저장되었습니다. (주휴수당 기능은 추후 업데이트 예정)', 'info');\r\n");
      out.write("    bootstrap.Modal.getInstance(document.getElementById('storeSettingModal')).hide();\r\n");
      out.write("}\r\n");
      out.write("\r\n");
      out.write("// 근무 설정 모달 열기\r\n");
      out.write("function openWorkSettingModal(memId, memName, workStart, workEnd, workType) {\r\n");
      out.write("    document.getElementById('wsMemId').value       = memId;\r\n");
      out.write("    document.getElementById('workSettingName').innerText = '- ' + memName;\r\n");
      out.write("    document.getElementById('wsStart').value = workStart || '';\r\n");
      out.write("    document.getElementById('wsEnd').value   = workEnd   || '';\r\n");
      out.write("\r\n");
      out.write("    // 라디오 선택\r\n");
      out.write("    document.querySelectorAll('input[name=\"wsType\"]').forEach(function(r) {\r\n");
      out.write("        r.checked = (r.value === workType);\r\n");
      out.write("    });\r\n");
      out.write("\r\n");
      out.write("    updateWagePreview();\r\n");
      out.write("    var modal = new bootstrap.Modal(document.getElementById('workSettingModal'));\r\n");
      out.write("    modal.show();\r\n");
      out.write("}\r\n");
      out.write("\r\n");
      out.write("// 시급 미리보기 업데이트\r\n");
      out.write("function updateWagePreview() {\r\n");
      out.write("    var startVal = document.getElementById('wsStart').value;\r\n");
      out.write("    var endVal   = document.getElementById('wsEnd').value;\r\n");
      out.write("    var typeEl   = document.querySelector('input[name=\"wsType\"]:checked');\r\n");
      out.write("    var preview  = document.getElementById('wagePreview');\r\n");
      out.write("\r\n");
      out.write("    if (!startVal || !endVal || !typeEl) {\r\n");
      out.write("        preview.innerHTML = '<span class=\"text-muted small\">시간대·유형을 선택하면 표시됩니다.</span>';\r\n");
      out.write("        return;\r\n");
      out.write("    }\r\n");
      out.write("\r\n");
      out.write("    var startH   = parseInt(startVal.split(':')[0]);\r\n");
      out.write("    var endH     = parseInt(endVal.split(':')[0]);\r\n");
      out.write("    var workType = typeEl.value;\r\n");
      out.write("    var html     = '';\r\n");
      out.write("\r\n");
      out.write("    var isNight  = endH >= 22 || endH < 6 || startH < 6;\r\n");
      out.write("    var hasDay   = startH < 22 && endH > 6;\r\n");
      out.write("\r\n");
      out.write("    if (workType === '평일' || workType === '전체') {\r\n");
      out.write("        if (hasDay)   html += '<span class=\"badge bg-primary\">평일주간 ×1.0</span> ';\r\n");
      out.write("        if (isNight)  html += '<span class=\"badge bg-dark\">평일야간 ×1.5</span> ';\r\n");
      out.write("    }\r\n");
      out.write("    if (workType === '주말' || workType === '전체') {\r\n");
      out.write("        if (hasDay)   html += '<span class=\"badge bg-warning text-dark\">주말주간 ×1.5</span> ';\r\n");
      out.write("        if (isNight)  html += '<span class=\"badge bg-danger\">주말야간 ×2.0</span> ';\r\n");
      out.write("    }\r\n");
      out.write("\r\n");
      out.write("    preview.innerHTML = html || '<span class=\"text-muted small\">해당 없음</span>';\r\n");
      out.write("}\r\n");
      out.write("\r\n");
      out.write("// 근무 설정 저장\r\n");
      out.write("async function saveWorkSetting() {\r\n");
      out.write("    var memId    = document.getElementById('wsMemId').value;\r\n");
      out.write("    var storeId  = document.getElementById('wsStoreId').value;\r\n");
      out.write("    var start    = document.getElementById('wsStart').value;\r\n");
      out.write("    var end      = document.getElementById('wsEnd').value;\r\n");
      out.write("    var typeEl   = document.querySelector('input[name=\"wsType\"]:checked');\r\n");
      out.write("\r\n");
      out.write("    if (!start || !end) { showToast('근무 시간을 입력해주세요.', 'warning'); return; }\r\n");
      out.write("    if (!typeEl)        { showToast('근무 유형을 선택해주세요.', 'warning'); return; }\r\n");
      out.write("\r\n");
      out.write("    var params = new URLSearchParams();\r\n");
      out.write("    params.append('action',     'saveWorkSetting');\r\n");
      out.write("    params.append('memId',      memId);\r\n");
      out.write("    params.append('storeId',    storeId);\r\n");
      out.write("    params.append('workStart',  start);\r\n");
      out.write("    params.append('workEnd',    end);\r\n");
      out.write("    params.append('workType',   typeEl.value);\r\n");
      out.write("\r\n");
      out.write("    try {\r\n");
      out.write("        var res  = await fetch('StoreMemberManage', { method: 'POST', body: params });\r\n");
      out.write("        var data = await res.json();\r\n");
      out.write("        showToast(data.message, data.status === 'success' ? 'success' : 'danger');\r\n");
      out.write("        if (data.status === 'success') {\r\n");
